import { Link } from "react-router-dom";

function MatchCard({ match }) {
  const teamAPlayers = match.players?.filter(p => p.team === match.teamA) || [];
  const teamBPlayers = match.players?.filter(p => p.team === match.teamB) || [];

  const getTopPlayer = (players) => {
    return players.length > 0
      ? players.reduce((prev, current) => 
          prev.runs > current.runs ? prev : current
        )
      : null;
  };

  const teamATop = getTopPlayer(teamAPlayers);
  const teamBTop = getTopPlayer(teamBPlayers);

  return (
    <div className="card match-card">
      {match.status === "Completed" ? (
        <div style={{ marginBottom: '15px' }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '10px', marginBottom: '10px' }}>
            <div style={{ textAlign: 'center', padding: '10px', backgroundColor: '#f5f5f5', borderRadius: '4px' }}>
              <p style={{ margin: '0 0 5px 0', fontSize: '14px', fontWeight: '600' }}>{match.teamA}</p>
              <p style={{ margin: '0', fontSize: '20px', fontWeight: 'bold', color: match.winner === match.teamA ? '#28a745' : '#666' }}>{match.scoreA}</p>
            </div>
            <div style={{ textAlign: 'center', padding: '10px', backgroundColor: '#f5f5f5', borderRadius: '4px' }}>
              <p style={{ margin: '0 0 5px 0', fontSize: '14px', fontWeight: '600' }}>{match.teamB}</p>
              <p style={{ margin: '0', fontSize: '20px', fontWeight: 'bold', color: match.winner === match.teamB ? '#28a745' : '#666' }}>{match.scoreB}</p>
            </div>
          </div>

          <div style={{ backgroundColor: '#e8f5e9', padding: '10px', borderRadius: '4px', marginBottom: '10px' }}>
            {match.winner ? (
              <>
                <p style={{ margin: '0 0 5px 0', fontSize: '13px' }}><strong>🏆 Winner:</strong> <span style={{ fontSize: '15px', fontWeight: 'bold', color: '#28a745' }}>{match.winner}</span></p>
                {match.winType && (
                  <p style={{ margin: '0 0 5px 0', fontSize: '13px' }}><strong>Win Type:</strong> {match.winType} {match.winMargin ? `(${match.winMargin})` : ""}</p>
                )}
                {match.manOfMatch && (
                  <p style={{ margin: '0', fontSize: '13px' }}><strong>🌟 Man of Match:</strong> {match.manOfMatch}</p>
                )}
              </>
            ) : (
              <p style={{ margin: '0', color: '#999', fontSize: '13px' }}>Result not updated yet</p>
            )}
          </div>
        </div>
      ) : (
        <>
          <h4>{match.teamA} vs {match.teamB}</h4>
          <p className="score">{match.scoreA} | {match.scoreB}</p>
          <p>Status: <span style={{ color: match.status === 'Live' ? 'red' : '#666', fontWeight: 'bold' }}>{match.status}</span></p>
        </>
      )}

      {match.status !== "Completed" && (
        <div className="match-card-players">
          {teamATop && (
            <div className="top-player">
              <p className="player-name">{teamATop.name}</p>
              <div className="player-mini-stats">
                <span>{teamATop.runs} runs</span>
                <span>SR: {teamATop.strikeRate.toFixed(1)}</span>
              </div>
            </div>
          )}
          {teamBTop && (
            <div className="top-player">
              <p className="player-name">{teamBTop.name}</p>
              <div className="player-mini-stats">
                <span>{teamBTop.runs} runs</span>
                <span>SR: {teamBTop.strikeRate.toFixed(1)}</span>
              </div>
            </div>
          )}
        </div>
      )}

      <Link to={`/matches/${match._id}`} className="button-link">View Full Details</Link>
    </div>
  );
}

export default MatchCard;
